 1→import { Controller, Get, Header, Query } from '@nestjs/common';
 2→import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
 3→
 4→import { NeuralSearchService } from '@modules/rest/neural-search/neural-search.service';
 5→
 6→import { LogExecution } from '@decorators/log-execution.decorator';
 7→
 8→import { NeuralSearchQueryDto } from '@dto/neural-search/neural-search-query.dto';
 9→import { NeuralSearchResponseDto } from '@dto/neural-search/neural-search-response.dto';
10→
11→@ApiTags('Neural Search')
12→@Controller('neural-search')
13→export class NeuralSearchController {
14→	constructor(private readonly neuralSearchService: NeuralSearchService) {}
15→
16→	@Get()
17→	@ApiOperation({
18→		summary: 'Search products using natural language via neural embeddings',
19→	})
20→	@ApiResponse({
21→		status: 200,
22→		description: 'Returns semantically relevant products',
23→		type: NeuralSearchResponseDto,
24→	})
25→	@ApiResponse({ status: 400, description: 'Invalid query parameters' })
26→	@LogExecution({
27→		paramFormatter: (params: [NeuralSearchQueryDto]) => ({
28→			q: params[0].q,
29→			limit: params[0].limit,
30→		}),
31→		responseFormatter: (response: NeuralSearchResponseDto) => ({
32→			total: response.total,
33→		}),
34→	})
35→	async search(@Query() query: NeuralSearchQueryDto): Promise<NeuralSearchResponseDto> {
36→		return this.neuralSearchService.search({ query });
37→	}
38→
39→	@Get('view')
40→	@ApiOperation({ summary: 'Visual HTML view of neural search results' })
41→	@ApiResponse({ status: 200, description: 'Returns HTML page with product cards' })
42→	@Header('Content-Type', 'text/html')
43→	async view(@Query('q') q?: string, @Query('limit') limit?: string): Promise<string> {
44→		if (!q) {
45→			return this.neuralSearchService.renderSearchPageHtml({ result: null });
46→		}
47→
48→		const query: NeuralSearchQueryDto = {
49→			q,
50→			...(limit !== undefined && { limit: Number(limit) }),
51→		};
52→		const result = await this.neuralSearchService.search({ query });
53→
54→		return this.neuralSearchService.renderSearchPageHtml({ result });
55→	}
56→}
