  1→import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
  2→import { Interval } from '@nestjs/schedule';
  3→
  4→import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
  5→import { EnvConfigService } from '@modules/env-config/env-config.service';
  6→import { OpensearchService } from '@modules/opensearch/opensearch.service';
  7→
  8→import {
  9→	NEURAL_SEARCH_LIMIT,
 10→	NEURAL_SEARCH_MAX_QUERY_LENGTH,
 11→} from '@constants/common.constant';
 12→import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
 13→import { NEURAL_SEARCH_KNOWN_BRANDS } from '@constants/neural-search-brands.constant';
 14→
 15→import { IOpensearchProduct } from '@interfaces/opensearch-product.interface';
 16→
 17→import { LogExecution } from '@decorators/log-execution.decorator';
 18→
 19→const MODEL_REFRESH_INTERVAL_MS = 5 * 60 * 1000;
 20→
 21→const MODEL_GROUP_NAME = 'neural-search-model-group';
 22→
 23→@Injectable()
 24→export class OpensearchNeuralService implements OnModuleInit {
 25→	private readonly logger = new Logger(OpensearchNeuralService.name);
 26→	private indexName: string;
 27→	private modelId: string | null = null;
 28→
 29→	constructor(
 30→		private readonly opensearchService: OpensearchService,
 31→		private readonly configService: EnvConfigService,
 32→	) {}
 33→
 34→	async onModuleInit(): Promise<void> {
 35→		this.indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
 36→		await this.resolveModelId();
 37→	}
 38→
 39→	@Interval(MODEL_REFRESH_INTERVAL_MS)
 40→	async refreshModelId(): Promise<void> {
 41→		await this.resolveModelId();
 42→	}
 43→
 44→	private async resolveModelId(): Promise<void> {
 45→		try {
 46→			const modelId = await this.opensearchService.findDeployedModelId({
 47→				modelGroupName: MODEL_GROUP_NAME,
 48→			});
 49→
 50→			if (modelId && modelId !== this.modelId) {
 51→				const previousModelId = this.modelId;
 52→				this.modelId = modelId;
 53→				this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
 54→			} else if (!modelId) {
 55→				this.logger.warn(
 56→					'No deployed model found. Neural search will not work until bootstrap is run.',
 57→				);
 58→			}
 59→		} catch {
 60→			this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
 61→		}
 62→	}
 63→
 64→	private getModelId(): string {
 65→		if (!this.modelId) {
 66→			throw new Error(
 67→				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
 68→			);
 69→		}
 70→		return this.modelId;
 71→	}
 72→
 73→	private detectBrand({ text }: { text: string }): string | null {
 74→		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
 75→		for (const brand of sorted) {
 76→			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 77→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
 78→				return brand;
 79→			}
 80→		}
 81→		return null;
 82→	}
 83→
 84→	private readonly GENDER_PRODUCT_TYPE_MAP: {
 85→		pattern: RegExp;
 86→		productTypes: string[];
 87→	}[] = [
 88→		{
 89→			pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
 90→			productTypes: ["Women's"],
 91→		},
 92→		{
 93→			pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
 94→			productTypes: ['Unisex'],
 95→		},
 96→		{
 97→			pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
 98→			productTypes: ['Youth'],
 99→		},
100→	];
101→
102→	private detectGenderProductTypes({ text }: { text: string }): string[] | null {
103→		const productTypes: string[] = [];
104→
105→		for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
106→			if (pattern.test(text)) {
107→				productTypes.push(...types);
108→			}
109→		}
110→
111→		return productTypes.length > 0 ? productTypes : null;
112→	}
113→
114→	private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
115→		{
116→			pattern:
117→				/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
118→			levels: [1],
119→		},
120→		{
121→			pattern:
122→				/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
123→			levels: [2],
124→		},
125→		{
126→			pattern:
127→				/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest)\b/i,
128→			levels: [3],
129→		},
130→	];
131→
132→	private detectPriceLevels({ text }: { text: string }): number[] | null {
133→		const levels: number[] = [];
134→
135→		for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
136→			if (pattern.test(text)) {
137→				levels.push(...priceLevels);
138→			}
139→		}
140→
141→		return levels.length > 0 ? levels : null;
142→	}
143→
144→	private sanitizeQuery({ text }: { text: string }): string {
145→		return text
146→			.trim()
147→			.replace(/<[^>]*>/g, ' ')
148→			.replace(/[\x00-\x1F\x7F]/g, ' ')
149→			.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
150→			.replace(/\s{2,}/g, ' ')
151→			.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
152→			.trim();
153→	}
154→
155→	private readonly QUERY_SYNONYMS: [RegExp, string][] = [
156→		[/\btshirt(s)?\b/gi, 't-shirt$1'],
157→		[/\bt shirt(s)?\b/gi, 't-shirt$1'],
158→		[/\bv[\s-]?neck\b/gi, 'v-neck'],
159→		[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
160→		[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
161→		[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
162→		[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
163→		[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
164→		[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
165→		[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
166→		[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
167→		[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
168→		[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
169→		[/\bslim[\s-]?fit\b/gi, 'slim fit'],
170→		[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
171→	];
172→
173→	private normalizeQuery({ text }: { text: string }): string {
174→		let normalized = text.toLowerCase().trim();
175→
176→		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
177→			normalized = normalized.replace(pattern, replacement);
178→		}
179→
180→		return normalized;
181→	}
