183→	@LogExecution()
184→	async createProductsIndex({ indexName }: { indexName: string }): Promise<void> {
185→		const settings = {
186→			number_of_shards: 3,
187→			number_of_replicas: 1,
188→			'index.knn': true,
189→			'index.knn.algo_param.ef_search': 512,
190→			default_pipeline: 'products-neural-pipeline',
191→		};
192→
193→		const mappings = {
194→			properties: {
195→				style_id: { type: 'long' },
196→				product_id: { type: 'long' },
197→				name: { type: 'text' },
198→				features: { type: 'text' },
199→				general_comments: { type: 'text' },
200→				decoration_method: { type: 'text' },
201→				manufacturer: { type: 'text' },
202→				primary_category_id: { type: 'integer' },
203→				primary_category_name: { type: 'keyword' },
204→				product_type: { type: 'keyword' },
205→				style_type: { type: 'keyword' },
206→				broad_category_names: { type: 'keyword' },
207→				sub_category_names: { type: 'keyword' },
208→				minimum_quantity: { type: 'integer' },
209→				min_qty: { type: 'integer' },
210→				default_quote_qty: { type: 'integer' },
211→				sizes: { type: 'keyword' },
212→				turn_time: { type: 'integer' },
213→				rush_turn_time: { type: 'integer' },
214→				no_minimum: { type: 'byte' },
215→				price_level: { type: 'short' },
216→				rating_score: { type: 'float' },
217→				rating_count: { type: 'integer' },
218→				default_unit_prices: {
219→					type: 'nested',
220→					properties: {
221→						quantity: { type: 'integer' },
222→						price: { type: 'keyword' },
223→						regular_unit_price: { type: 'keyword' },
224→						algorithm: { type: 'keyword' },
225→					},
226→				},
227→				colors: {
228→					type: 'nested',
229→					properties: {
230→						name: { type: 'keyword' },
231→						id: { type: 'integer' },
232→						rbgs: {
233→							type: 'nested',
234→							properties: {
235→								R: { type: 'short' },
236→								G: { type: 'short' },
237→								B: { type: 'short' },
238→							},
239→						},
240→						image_url: { type: 'keyword' },
241→					},
242→				},
243→				style_card_image_url: { type: 'keyword' },
244→				link: { type: 'keyword' },
245→				brand: { type: 'keyword' },
246→				condensed_features: { type: 'keyword' },
247→				material: { type: 'keyword' },
248→				status: { type: 'keyword' },
249→				created_at: { type: 'date' },
250→				updated_at: { type: 'date' },
251→				deleted_at: { type: 'date' },
252→				combined_text_for_embedding: { type: 'text' },
253→				product_embedding: {
254→					type: 'knn_vector',
255→					dimension: 768,
256→					method: {
257→						name: 'hnsw',
258→						space_type: 'l2',
259→						engine: 'faiss',
260→						parameters: { ef_construction: 512, m: 48 },
261→					},
262→				},
263→			},
264→		};
265→
266→		await this.opensearchService.createIndex({ indexName, mappings, settings });
267→	}
