269→	@LogExecution({ logParams: false, logResponse: false })
270→	async bulkIndexProducts({
271→		indexName,
272→		styles,
273→	}: {
274→		indexName: string;
275→		styles: IStylesMvBase[];
276→	}): Promise<{ indexed: number; errors: number }> {
277→		if (styles.length === 0) {
278→			return { indexed: 0, errors: 0 };
279→		}
280→
281→		const documents = styles.map((style) =>
282→			this.transformStyleToOpensearchProduct({ style }),
283→		);
284→
285→		return this.opensearchService.bulkIndex({ indexName, documents });
286→	}
287→
288→	@LogExecution({
289→		paramFormatter: (params: [{ queryText: string; size: number }]) => ({
290→			queryText: params[0].queryText,
291→			size: params[0].size,
292→		}),
293→		responseFormatter: (response: IOpensearchProduct[]) => ({
294→			totalResults: response.length,
295→		}),
296→	})
297→	async searchProducts({
298→		queryText,
299→		size = NEURAL_SEARCH_LIMIT,
300→	}: {
301→		queryText: string;
302→		size?: number;
303→	}): Promise<IOpensearchProduct[]> {
304→		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
305→		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
306→		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
307→		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
308→		const brand = this.detectBrand({ text: sanitizedQuery });
309→
310→		const baseFilters: object[] = [{ term: { status: 'active' } }];
311→
312→		if (genderProductTypes) {
313→			baseFilters.push({ terms: { product_type: genderProductTypes } });
314→		}
315→
316→		const priceBoosts: object[] =
317→			priceLevels?.map((level) => ({
318→				term: { price_level: { value: level, boost: 1.5 } },
319→			})) ?? [];
320→
321→		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand], boost: 2 } }] : [];
322→
323→		const hits = await this.opensearchService.search({
324→			indexName: this.indexName,
325→			searchPipeline: 'hybrid-search-pipeline',
326→			body: {
327→				size,
328→				min_score: 0.4,
329→				query: {
330→					hybrid: {
331→						queries: [
332→							{
333→								bool: {
334→									should: [
335→										{
336→											match_phrase: {
337→												general_comments: { query: normalizedQuery, boost: 0.1 },
338→											},
339→										},
340→										{
341→											match_phrase: { features: { query: normalizedQuery, boost: 0.1 } },
342→										},
343→										{ match_phrase: { name: { query: normalizedQuery, boost: 0.1 } } },
344→										...priceBoosts,
345→										...brandBoosts,
346→									],
347→									filter: baseFilters,
348→								},
349→							},
350→							{
351→								neural: {
352→									product_embedding: {
353→										query_text: normalizedQuery,
354→										model_id: this.getModelId(),
355→										k: size * 5,
356→										filter: { bool: { filter: baseFilters } },
357→									},
358→								},
359→							},
360→						],
361→					},
362→				},
363→				collapse: { field: 'product_id' },
364→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
365→			},
366→		});
367→
368→		return hits.map((hit) => ({
369→			...(hit._source as IOpensearchProduct),
370→			_id: hit._id,
371→		}));
372→	}
373→
374→	private normalizeCondensedFeatures({
375→		condensedFeatures,
376→	}: {
377→		condensedFeatures: unknown;
378→	}): string[] | null {
379→		if (condensedFeatures === null || condensedFeatures === undefined) {
380→			return null;
381→		}
382→
383→		if (typeof condensedFeatures === 'string') {
384→			return [condensedFeatures];
385→		}
386→
387→		if (Array.isArray(condensedFeatures)) {
388→			return condensedFeatures.map(String);
389→		}
390→
391→		if (typeof condensedFeatures === 'object') {
392→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
393→				Array.isArray(value) ? value.map(String) : [String(value)],
394→			);
395→		}
396→
397→		return [JSON.stringify(condensedFeatures)];
398→	}
399→
400→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
401→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
402→			condensedFeatures: style.condensed_features,
403→		});
404→		const priceLvlMap: Record<string, string> = {
405→			1: 'Budget',
406→			2: 'Mid-range',
407→			3: 'Premium',
408→		};
409→		const mappedPriceLevel: string | null =
410→			style.price_level && priceLvlMap[String(style.price_level)]
411→				? (priceLvlMap[String(style.price_level)] ?? null)
412→				: (priceLvlMap['2'] ?? null);
413→
414→		const parts: string[] = [
415→			...(style.name ? [this.cleanText({ text: style.name })] : []),
416→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
417→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
418→			...(style.brand?.length
419→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
420→				: []),
421→			...(normalizedCondensedFeatures?.length
422→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
423→				: []),
424→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
425→			...(style.primary_category_name
426→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
427→				: []),
428→			...(style.manufacturer
429→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
430→				: []),
431→			...(style.sub_category_names?.length
432→				? [
433→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
434→					]
435→				: []),
436→			...(style.decoration_method
437→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
438→				: []),
439→			...(style.features
440→				? [`Features: ${this.cleanText({ text: style.features })}`]
441→				: []),
442→		];
443→
444→		const combinedText = parts.filter(Boolean).join('. ');
445→
446→		this.logger.debug(
447→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
448→		);
449→
450→		return combinedText;
451→	}
452→
453→	private cleanText({ text }: { text: string | null | undefined }): string {
454→		if (!text) return '';
455→		return text
456→			.replace(/\r\n|\r|\n/g, ' ')
457→			.replace(/[*#]+\s?/g, '')
458→			.replace(/<[^>]*>/g, '')
459→			.replace(/\s{2,}/g, ' ')
460→			.trim();
461→	}
462→
463→	private transformStyleToOpensearchProduct({
464→		style,
465→	}: {
466→		style: IStylesMvBase;
467→	}): IOpensearchProduct {
468→		return {
469→			_id: style._id,
470→			style_id: style.style_id,
471→			product_id: style.product_id,
472→			name: style.name ?? '',
473→			features: style.features,
474→			general_comments: style.general_comments,
475→			decoration_method: style.decoration_method,
476→			manufacturer: style.manufacturer,
477→			primary_category_id: style.primary_category_id,
478→			primary_category_name: style.primary_category_name,
479→			product_type: style.product_type,
480→			style_type: style.style_type,
481→			broad_category_names: style.broad_category_names,
482→			sub_category_names: style.sub_category_names,
483→			minimum_quantity: style.minimum_quantity,
484→			min_qty: style.min_qty,
485→			default_quote_qty: style.default_quote_qty,
486→			sizes: style.sizes,
487→			turn_time: style.turn_time,
488→			rush_turn_time: style.rush_turn_time,
489→			no_minimum: style.no_minimum ? 1 : 0,
490→			price_level: style.price_level,
491→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
492→			rating_count: style.rating_count,
493→			default_unit_prices: style.default_unit_prices,
494→			colors: style.colors,
495→			style_card_image_url: style.style_card_image_url,
496→			link: style.link,
497→			brand: style.brand,
498→			condensed_features: this.normalizeCondensedFeatures({
499→				condensedFeatures: style.condensed_features,
500→			}),
501→			material: style.material,
502→			status: style.status,
503→			created_at:
504→				style.created_at instanceof Date
505→					? style.created_at.toISOString()
506→					: String(style.created_at),
507→			updated_at:
508→				style.updated_at instanceof Date
509→					? style.updated_at.toISOString()
510→					: String(style.updated_at),
511→			deleted_at: style.deleted_at
512→				? style.deleted_at instanceof Date
513→					? style.deleted_at.toISOString()
514→					: String(style.deleted_at)
515→				: null,
516→			combined_text_for_embedding: this.buildCombinedTextForEmbedding({ style }),
517→		};
518→	}
