513→			const hits = (response.body as { hits: { hits: { _id: string }[] } }).hits.hits;
514→			return hits[0]?._id ?? null;
515→		} catch (error: unknown) {
516→			this.handleError({ context: `Failed to search model group: ${name}`, error });
517→			throw error;
518→		}
519→	}
520→
521→	@LogExecution()
522→	async undeployModel({ modelId }: { modelId: string }): Promise<void> {
523→		try {
524→			await this.client.transport.request({
525→				method: 'POST',
526→				path: `/_plugins/_ml/models/${modelId}/_undeploy`,
527→			});
528→			this.logger.log(`Undeployed model: ${modelId}`);
529→		} catch (error: unknown) {
530→			this.handleError({ context: `Failed to undeploy model ${modelId}`, error });
531→			throw error;
532→		}
533→	}
534→
535→	@LogExecution()
536→	async deleteModel({ modelId }: { modelId: string }): Promise<void> {
537→		try {
538→			await this.client.transport.request({
539→				method: 'DELETE',
540→				path: `/_plugins/_ml/models/${modelId}`,
541→			});
542→			this.logger.log(`Deleted model: ${modelId}`);
543→		} catch (error: unknown) {
544→			this.handleError({ context: `Failed to delete model ${modelId}`, error });
545→			throw error;
546→		}
547→	}
548→
549→	@LogExecution()
550→	async deleteModelGroup({ modelGroupId }: { modelGroupId: string }): Promise<void> {
551→		try {
552→			await this.client.transport.request({
553→				method: 'DELETE',
554→				path: `/_plugins/_ml/model_groups/${modelGroupId}`,
555→			});
556→			this.logger.log(`Deleted model group: ${modelGroupId}`);
557→		} catch (error: unknown) {
558→			this.handleError({
559→				context: `Failed to delete model group ${modelGroupId}`,
560→				error,
561→			});
562→			throw error;
563→		}
564→	}
565→
566→	@LogExecution()
567→	async findDeployedModelId({
568→		modelGroupName,
569→	}: {
570→		modelGroupName: string;
571→	}): Promise<string | null> {
572→		const modelGroupId = await this.searchModelGroupByName({ name: modelGroupName });
573→
574→		if (!modelGroupId) {
575→			return null;
576→		}
577→
578→		const models = await this.searchModelsByGroup({ modelGroupId });
579→		const deployed = models.find((m) => m.model_state === 'DEPLOYED');
580→		return deployed?.model_id ?? null;
581→	}
582→
583→	private isNotFoundError({ error }: { error: unknown }): boolean {
584→		const message = error instanceof Error ? error.message : String(error);
585→		return message.includes('resource_not_found') || message.includes('404');
586→	}
587→
588→	private handleError({ context, error }: { context: string; error: unknown }): void {
589→		const err = error instanceof Error ? error : new Error(String(error));
590→		this.logger.error(`${context}: ${err.message}`, err.stack);
591→	}
