  2→import { OpenAI } from 'openai';
  3→
  4→import { getEnv } from '@utils/get-env-variable.util';
  5→
  6→import { OPENAI_API_KEY } from '@constants/env-variables.constant';
  7→
  8→import { MMSStyleToProcess } from '@interfaces/mms-style-to-process.interface';
