 27→	logExecutionTime: true,
 28→	logErrToRollbar: true,
 29→	logLongExecution: true,
 30→	rollbarLevel: 'debug',
 31→	maskSensitiveData: true,
 32→	sensitiveKeys: [
 33→		'password',
 34→		'pass',
 35→		'token',
 36→		'secret',
 37→		'auth',
 38→		'authorization',
 39→		'cookie',
 40→		'session',
 41→		'credentials',
 42→		'apiKey',
 43→		'_cookie',
 44→		'csrf',
 45→		'_csrf',
 46→	],
 47→	paramFormatter: <TParams>(params: TParams) => params,
 48→	responseFormatter: <TResponse>(response: TResponse) => response,
 49→};
 50→
 51→const thresholdMs = Number(process.env[EXECUTION_TIME_THRESHOLD_MS]);
 52→
 53→export function LogExecution<TParams, TResponse>(
 54→	options: LogExecutionOptions<TParams, TResponse> = {},
 55→): MethodDecorator {
 56→	const config: LogExecutionOptions<TParams, TResponse> = {
 57→		...DEFAULT_OPTIONS,
 58→		...options,
 59→	};
 60→
 61→	return function (
 62→		target: unknown,
 63→		propertyKey: string | symbol,
 64→		descriptor: PropertyDescriptor,
 65→	) {
 66→		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
 67→		const className = (target as { constructor: { name: string } }).constructor.name;
 68→		const methodName = String(propertyKey);
 69→		const logger = new Logger(`${className}.${methodName}`);
 70→
 71→		descriptor.value = async function (...args: unknown[]) {
 72→			const startTime = performance.now();
 73→
 74→			try {
 75→				const logContext = {
 76→					className,
 77→					methodName,
 78→					timestamp: new Date().toISOString(),
 79→					...(config.customContext ?? {}),
 80→				};
 81→
 82→				let paramsToLog: unknown = config.paramFormatter
 83→					? config.paramFormatter(args as TParams)
 84→					: args;
 85→				if (config.maskSensitiveData) {
 86→					paramsToLog = maskSensitiveData(paramsToLog, config.sensitiveKeys);
 87→				}
 88→
 89→				if (config.logParams) {
 90→					logger.log(
 91→						`[LogExecution]: Method invoked with parameters, ${JSON.stringify({
 92→							params: paramsToLog,
 93→							...logContext,
 94→						})}`,
 95→					);
 96→				}
 97→
 98→				const result = await originalMethod.apply(this, args);
 99→				const endTime = performance.now();
100→				const executionTime = endTime - startTime;
101→
102→				let responseToLog: unknown = config.responseFormatter
103→					? config.responseFormatter(result as TResponse)
104→					: result;
105→				if (config.maskSensitiveData) {
106→					responseToLog = maskSensitiveData(responseToLog, config.sensitiveKeys);
107→				}
108→
109→				const successLogContext = {
110→					...logContext,
111→					executionTimeMs: executionTime,
112→					response: config.logResponse ? responseToLog : undefined,
113→				};
114→
115→				if (config.logExecutionTime) {
116→					logger.log(
117→						`[LogExecution]:Method completed in ${executionTime.toFixed(2)}ms. Result: ${JSON.stringify(successLogContext)}`,
118→					);
119→				}
120→
121→				if (executionTime > thresholdMs) {
122→					logger.warn(
123→						`[LogExecution]: Long execution ${executionTime.toFixed(
124→							2,
125→						)}ms, logContext: ${JSON.stringify({ ...successLogContext, success: true })}`,
126→					);
127→
128→					if (config.logLongExecution) {
129→						try {
130→							const rollbar = getRollbarInstance();
131→							if (rollbar) {
132→								rollbar.warning(
133→									`[LogExecution]: Long execution ${executionTime.toFixed(2)}ms.`,
134→									{ ...successLogContext, success: true },
135→								);
136→							}
137→						} catch {}
138→					}
139→				}
140→
141→				return result;
142→			} catch (error) {
143→				const endTime = performance.now();
144→				const executionTime = endTime - startTime;
145→				const errorLogContext = {
146→					className,
147→					methodName,
148→					timestamp: new Date().toISOString(),
149→					executionTimeMs: executionTime,
150→					error: {
151→						message: (error as Error).message,
152→						stack: (error as Error).stack,
153→						name: (error as Error).name,
154→					},
155→					...(config.customContext ?? {}),
156→				};
157→
158→				logger.error(
159→					`[LogExecution]: Method failed after ${executionTime.toFixed(2)}ms: ${
160→						(error as Error).message
161→					}, errorLogContext: ${JSON.stringify(errorLogContext)}`,
162→				);
163→
164→				if (config.logErrToRollbar) {
165→					try {
166→						const rollbar = getRollbarInstance();
167→						if (rollbar) {
168→							rollbar.error(`Method ${className}.${methodName} failed.`, error as Error, {
169→								...errorLogContext,
170→								success: false,
171→							});
172→						}
173→					} catch {}
174→				}
175→
176→				throw error;
177→			}
178→		};
179→
180→		return descriptor;
181→	};
182→}
183→
184→function maskSensitiveData(data: unknown, sensitiveKeys: string[] = []): unknown {
185→	if (!data || typeof data !== 'object') {
186→		return data;
187→	}
188→
189→	if (Array.isArray(data)) {
190→		return data.map((item) => maskSensitiveData(item, sensitiveKeys));
191→	}
192→
193→	const masked = { ...data } as Record<string, unknown>;
194→
195→	for (const key in masked) {
196→		if (Object.prototype.hasOwnProperty.call(masked, key)) {
197→			const lowerKey = key.toLowerCase();
198→
199→			if (
200→				sensitiveKeys.some((sensitiveKey) =>
201→					lowerKey.includes(sensitiveKey.toLowerCase()),
202→				)
203→			) {
204→				masked[key] = '***MASKED***';
205→			} else if (typeof masked[key] === 'object' && masked[key] !== null) {
206→				masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
207→			}
208→		}
209→	}
210→
211→	return masked;
212→}
213→
214→function getRollbarInstance(): Rollbar | null {
215→	return rollbar;
216→}
