 1→import { Injectable, Logger } from '@nestjs/common';
 2→import { ConfigService } from '@nestjs/config';
 3→
 4→@Injectable()
 5→export class EnvConfigService {
 6→	private readonly logger = new Logger(EnvConfigService.name);
 7→
 8→	constructor(private readonly configService: ConfigService) {}
 9→
10→	get<T = unknown>({
11→		key,
12→		converter,
13→	}: {
14→		key: string;
15→		converter?: (param: unknown) => T;
16→	}): T {
17→		this.logger.log(
18→			`Fetching environment variable: ${key}, converter: ${converter ? converter.name : 'none'}`,
19→		);
20→		const envVariable = this.configService.get<T>(key);
21→
22→		if (envVariable === undefined) {
23→			throw new Error(`Environment variable ${key} is not defined`);
24→		}
25→
26→		return converter ? converter(envVariable) : envVariable;
27→	}
28→}
